    ctx.addIssue({ path: ["nodes", index, "id"], message: `nodes[${index}].id must be unique` });
  }
  nodeIds.add(node.id);
}

for (const [index, edge] of artifact.edges.entries()) {
  if (!nodeIds.has(edge.source)) {
    ctx.addIssue({ path: ["edges", index, "source"], message: `edges[${index}].source must reference an existing node` });
  }
  if (!nodeIds.has(edge.target)) {
    ctx.addIssue({ path: ["edges", index, "target"], message: `edges[${index}].target must reference an existing node` });
  }
}

